import { SCHOOLS, SCHOOL_TREND, DISTRICT_TREND, INTERVENTIONS_LOG, DISTRICT_KPIS } from './mockData';

// Helper to simulate network delay
const delay = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

export async function fetchSchools() {
  await delay(700);
  return SCHOOLS;
}

export async function fetchDistrictTrend() {
  await delay(800);
  return DISTRICT_TREND;
}

export async function fetchSchoolTrend(schoolId) {
  await delay(600);
  const trend = SCHOOL_TREND[schoolId];
  if (trend) return trend;
  
  // Fallback auto-generated trend for schools without explicit ones
  const school = SCHOOLS.find(s => s.id === schoolId);
  return DISTRICT_TREND.map(d => ({
    ...d,
    reading: Math.max(0, school.reading - 5 + Math.random() * 3),
    arithmetic: Math.max(0, school.arithmetic - 5 + Math.random() * 3),
    standard: school.standard
  }));
}

export async function fetchInterventions() {
  await delay(750);
  return INTERVENTIONS_LOG;
}

export async function fetchDistrictKpis() {
  await delay(650);
  return DISTRICT_KPIS;
}
